  1	import * as React from 'react';
  2	import { useExistingFileSystemNames } from '@odf/core/components/create-storage-system/external-systems/common/useResourceNameValidation';
  3	import { filterUsedDiscoveredDevices } from '@odf/core/components/utils';
  4	import { DiscoveredDevice, LocalDiskKind } from '@odf/core/types/scale';
  5	import {
  6	  PageHeading,
  7	  useCustomTranslation,
  8	  ButtonBar,
  9	  TextInputWithFieldRequirements,
 10	  LocalDiskModel,
 11	} from '@odf/shared';
 12	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 13	import * as _ from 'lodash-es';
 14	import { useNavigate } from 'react-router-dom-v5-compat';
 15	import {
 16	  Form,
 17	  FormGroup,
 18	  FormSection,
 19	  ActionGroup,
 20	  Button,
 21	  Alert,
 22	  AlertVariant,
 23	  ButtonType,
 24	  ButtonVariant,
 25	  FormHelperText,
 26	  HelperText,
 27	  HelperTextItem,
 28	} from '@patternfly/react-core';
 29	import { useIsLocalClusterConfigured } from '../common/hooks';
 30	import { NodesSection } from '../common/NodesSection';
 31	import {
 32	  configureMetricsNamespaceLabels,
 33	  createScaleLocalClusterPayload,
 34	  labelNodes,
 35	} from '../common/payload';
 36	import { LUNsTable } from './LUNsTable';
 37	import {
 38	  createCSIDriver,
 39	  createLocalDisks,
 40	  createLocalFileSystem,
 41	  createStorageClass,
 42	} from './payload';
 43	import { SANSystemComponentState, initialComponentState } from './types';
 44	import { useDeviceFinder } from './useDeviceFinder';
 45	import useSANSystemFormValidation from './useFormValidation';
 46	
 47	type CreateSANSystemFormProps = {
 48	  componentState: SANSystemComponentState;
 49	  setComponentState: React.Dispatch<
 50	    React.SetStateAction<SANSystemComponentState>
 51	  >;
 52	};
 53	
 54	const CreateSANSystemForm: React.FC<CreateSANSystemFormProps> = ({
 55	  componentState,
 56	  setComponentState,
 57	}) => {
 58	  const { t } = useCustomTranslation();
 59	  const navigate = useNavigate();
 60	  const [error, setError] = React.useState<string>('');
 61	  const [loading, setLoading] = React.useState(false);
 62	
 63	  const localCluster = useIsLocalClusterConfigured();
 64	  const isLocalClusterConfigured = !_.isEmpty(localCluster);
 65	
 66	  const [disks] = useK8sWatchResource<LocalDiskKind[]>({
 67	    groupVersionKind: {
 68	      group: LocalDiskModel.apiGroup,
 69	      version: LocalDiskModel.apiVersion,
 70	      kind: LocalDiskModel.kind,
 71	    },
 72	    isList: true,
 73	  });
 74	
 75	  const existingFileSystemNames = useExistingFileSystemNames();
 76	
 77	  const {
 78	    fieldRequirements,
 79	    control,
 80	    formState: { isSubmitted },
 81	    watch,
 82	  } = useSANSystemFormValidation(existingFileSystemNames);
 83	
 84	  const selectedNodes = componentState.selectedNodes;
 85	
 86	  const { sharedDevices, deviceFinderLoading } = useDeviceFinder(selectedNodes);
 87	
 88	  // Watch form fields
 89	  const lunGroupName = watch('lunGroupName');
 90	
 91	  const isFormValid = !!(
 92	    lunGroupName &&
 93	    componentState.selectedNodes.length > 0 &&
 94	    componentState.selectedLUNs.size > 0
 95	  );
 96	
 97	  const filteredSharedDevices = filterUsedDiscoveredDevices(
 98	    sharedDevices,
 99	    disks
100	  );
101	
102	  const onCreate = React.useCallback(async () => {
103	    setLoading(true);
104	    setError('');
105	
106	    const mappedLuns: DiscoveredDevice[] = sharedDevices.filter((lun) =>
107	      componentState.selectedLUNs.has(lun.WWN)
108	    );
109	    try {
110	      if (!isLocalClusterConfigured) {
111	        await labelNodes(componentState.selectedNodes)();
112	        await createScaleLocalClusterPayload()();
113	        await createCSIDriver();
114	        await configureMetricsNamespaceLabels();
115	      }
116	      const localDisks = await createLocalDisks(mappedLuns, t);
117	      const fileSystem = await createLocalFileSystem(
118	        lunGroupName,
119	        localDisks,
120	        t
121	      );
122	      await createStorageClass(fileSystem, t);
123	      navigate('/odf/external-systems');
124	    } catch (err) {
125	      setError(
126	        err instanceof Error
127	          ? err.message
128	          : t('An error occurred while creating the SAN system')
129	      );
130	    } finally {
131	      setLoading(false);
132	    }
133	  }, [
134	    sharedDevices,
135	    componentState.selectedLUNs,
136	    componentState.selectedNodes,
137	    isLocalClusterConfigured,
138	    lunGroupName,
139	    navigate,
140	    t,
141	  ]);
142	
143	  return (
144	    <Form isWidthLimited>
145	      <FormSection title={t('General configuration')}>
146	        <FormGroup label={t('Connection name')} fieldId="connectionName">
147	          <div data-test="san-connection-name">{t('SAN-based storage')}</div>
148	        </FormGroup>
149	        <FormGroup label={t('Select local cluster nodes')} isRequired>
150	          <NodesSection
151	            isDisabled={isLocalClusterConfigured}
152	            selectedNodes={componentState.selectedNodes}
153	            setSelectedNodes={(nodes) =>
154	              setComponentState((prev) => ({ ...prev, selectedNodes: nodes }))
155	            }
156	            allNodesDescription={t(
157	              'All non control plane nodes are selected to handle requests to IBM Scale'
158	            )}
159	            selectNodesDescription={t(
160	              'Select a minimum of 3 nodes to handle requests to IBM Scale'
161	            )}
162	          />
163	        </FormGroup>
164	      </FormSection>
165	      <FormSection title={t('LUN group details')}>
166	        <FormHelperText>
167	          <HelperText>
168	            <HelperTextItem>
169	              {t(
170	                'Select one or more of the shared LUNs accessible from all the selected local nodes above.'
171	              )}
172	            </HelperTextItem>
173	          </HelperText>
174	        </FormHelperText>
175	        <TextInputWithFieldRequirements
176	          control={control}
177	          fieldRequirements={fieldRequirements.lunGroupName}
178	          popoverProps={{
179	            headerContent: t('LUN group name requirements'),
180	            footerContent: `${t('Example')}: lun-group-a`,
181	          }}
182	          formGroupProps={{
183	            label: t('Name'),
184	            fieldId: 'lunGroupName',
185	            isRequired: true,
186	          }}
187	          textInputProps={{
188	            id: 'lunGroupName',
189	            name: 'lunGroupName',
190	            type: 'text',
191	            'data-test': 'lun-group-name',
192	          }}
193	        />
194	        <FormGroup label={t('LUNs')} isRequired>
195	          <LUNsTable
196	            luns={filteredSharedDevices}
197	            selectedLUNs={componentState.selectedLUNs}
198	            onLUNSelect={(selectedLUNs) =>
199	              setComponentState((prev) => ({ ...prev, selectedLUNs }))
200	            }
201	            loaded={!deviceFinderLoading}
202	          />
203	        </FormGroup>
204	      </FormSection>
205	      {!isFormValid && isSubmitted && (
206	        <Alert
207	          variant={AlertVariant.danger}
208	          isInline
209	          title={t('Address form errors to proceed')}
210	        />
211	      )}
212	      <ButtonBar errorMessage={error}>
213	        <ActionGroup className="pf-v6-c-form">
214	          <Button
215	            type={ButtonType.submit}
216	            variant={ButtonVariant.primary}
217	            isDisabled={loading || !isFormValid}
218	            isLoading={loading}
219	            data-test="connect-and-create-san-system"
220	            onClick={onCreate}
221	          >
222	            {t('Connect and create')}
223	          </Button>
224	          <Button
225	            onClick={() => navigate(-1)}
226	            type={ButtonType.button}
227	            variant={ButtonVariant.secondary}
228	          >
229	            {t('Cancel')}
230	          </Button>
231	        </ActionGroup>
232	      </ButtonBar>
233	    </Form>
234	  );
235	};
236	
237	export const CreateSANSystem: React.FC = () => {
238	  const [componentState, setComponentState] =
239	    React.useState<SANSystemComponentState>(initialComponentState);
240	  const { t } = useCustomTranslation();
241	
242	  return (
243	    <>
244	      <PageHeading
245	        title={t('Connect Storage Area Network')}
246	        hasUnderline={false}
247	        breadcrumbs={[
248	          {
249	            name: t('External Systems'),
250	            path: '/odf/external-systems',
251	          },
252	          {
253	            name: t('Connect Storage Area Network'),
254	            path: '/odf/external-systems/san/~create',
255	          },
256	        ]}
257	      >
258	        {t(
259	          'Use groups of shared LUNs from local cluster nodes to create StorageClasses with Fusion Data Foundation Access for SAN.'
260	        )}
261	      </PageHeading>
262	      <div className="odf-m-pane__body">
263	        <CreateSANSystemForm
264	          componentState={componentState}
265	          setComponentState={setComponentState}
266	        />
267	      </div>
268	    </>
269	  );
270	};
271	
272	export default CreateSANSystem;

